        id: "builder",
        fn: "Builder",
        desc: "Construct complex objects step by step with a fluent API.",
        category: "Creational",
        subtitle: "Fluent chain of setters, then build() — ideal for many optional params",
        signature: "new Builder().setA(1).setB(2).build()",
        descLong: "The Builder pattern constructs complex objects step by step using a fluent API. Each setter returns the builder, allowing chaining. A final build() method returns the constructed object. Ideal when an object has many optional parameters — avoids the \"telescoping constructor\" anti-pattern (constructor with 10 params, most optional).",
        examples: [
                  {
                            "tier": "intro",
                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of Builder — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - Fluent builder with method chaining\n// STRENGTHS - Shows the core builder pattern\n// WEAKNESSES- No validation, no immutability\n//\nclass PizzaBuilder {\n  #size; #cheese = false; #pepperoni = false; #mushrooms = false;\n  size(s) { this.#size = s; return this; }\n  addCheese() { this.#cheese = true; return this; }\n  addPepperoni() { this.#pepperoni = true; return this; }\n  addMushrooms() { this.#mushrooms = true; return this; }\n  build() {\n    return { size: this.#size, cheese: this.#cheese, pepperoni: this.#pepperoni, mushrooms: this.#mushrooms };\n  }\n}\nconst pizza = new PizzaBuilder()\n  .size('large')\n  .addCheese()\n  .addPepperoni()\n  .build();\nconsole.log(pizza);  // { size: 'large', cheese: true, pepperoni: true, mushrooms: false }"
                  },
                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Builder — common patterns you'll see in production.\n// APPROACH  - Combine Builder with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - Validation, immutability, director pattern\n// STRENGTHS - Production-ready builder with validation\n// WEAKNESSES- No reset, no partial builds\n//\nclass RequestBuilder {\n  #url; #method = 'GET'; #headers = {}; #body; #timeout = 5000;\n  url(u) { this.#url = u; return this; }\n  method(m) { this.#method = m; return this; }\n  header(k, v) { this.#headers[k] = v; return this; }\n  body(b) { this.#body = b; return this; }\n  timeout(t) { this.#timeout = t; return this; }\n  build() {\n    // Validation\n    if (!this.#url) throw new Error('URL is required');\n    if (!['GET', 'POST', 'PUT', 'DELETE', 'PATCH'].includes(this.#method)) {\n      throw new Error(`Invalid method: ${this.#method}`);\n    }\n    // Immutable result\n    return Object.freeze({\n      url: this.#url,\n      method: this.#method,\n      headers: Object.freeze({ ...this.#headers }),\n      body: this.#body,\n      timeout: this.#timeout,\n    });\n  }\n}\nconst req = new RequestBuilder()\n  .url('https://api.example.com/users')\n  .method('POST')\n  .header('Content-Type', 'application/json')\n  .header('Authorization', 'Bearer token123')\n  .body(JSON.stringify({ name: 'Alice' }))\n  .timeout(10000)\n  .build();\nconsole.log(req.method);  // 'POST'\n// req.method = 'GET';  // TypeError — frozen"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Builder — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - Director, reset, generic builder, decision guide\n// STRENGTHS - Advanced builder patterns for complex construction\n// WEAKNESSES- N/A\n//\n// 1) DIRECTOR — encapsulates common construction sequences\nclass RequestDirector {\n  #builder;\n  constructor(builder) { this.#builder = builder; }\n  buildGetRequest(url) {\n    return this.#builder.url(url).method('GET').timeout(3000).build();\n  }\n  buildJsonPost(url, body) {\n    return this.#builder\n      .url(url).method('POST')\n      .header('Content-Type', 'application/json')\n      .body(JSON.stringify(body))\n      .timeout(10000)\n      .build();\n  }\n  buildAuthedRequest(url, method, token) {\n    return this.#builder\n      .url(url).method(method)\n      .header('Authorization', `Bearer ${token}`)\n      .timeout(5000)\n      .build();\n  }\n}\nconst director = new RequestDirector(new RequestBuilder());\nconst authReq = director.buildAuthedRequest('https://api.example.com/data', 'GET', 'token123');\n// 2) RESET — reuse builder for multiple objects\nclass ResettableBuilder extends RequestBuilder {\n  reset() {\n    this.#url = undefined; this.#method = 'GET';\n    this.#headers = {}; this.#body = undefined; this.#timeout = 5000;\n    return this;\n  }\n}\n// 3) GENERIC BUILDER — works with any class\nfunction createBuilder(Class) {\n  return class {\n    #props = {};\n    set(prop, value) { this.#props[prop] = value; return this; }\n    build() { return new Class(this.#props); }\n  };\n}\n// Usage:\n// const UserBuilder = createBuilder(User);\n// const user = new UserBuilder().set('name', 'Alice').set('age', 30).build();\n// 4) BUILDER WITH PROXY — dynamic fluent API\nfunction fluentBuilder(defaults = {}) {\n  const props = { ...defaults };\n  return new Proxy({}, {\n    get(_, prop) {\n      if (prop === 'build') return () => Object.freeze(props);\n      return (value) => { props[prop] = value; return proxy; };\n    },\n  });\n  // Note: 'proxy' would need to be defined before the handler\n  // This is a simplified illustration — use a closure or ref\n}\n// Decision rule:\n//   many optional parameters (> 4)                       -> builder pattern\n//   telescoping constructor (many overloaded constructors) -> builder\n//   immutable result with validation                     -> builder + Object.freeze + validate in build()\n//   common construction sequences                       -> director on top of builder\n//   reuse builder for multiple objects                  -> reset() method\n//   need to construct different representations         -> separate builder per representation\n//   simple object with 2-3 params                        -> plain constructor or object literal\n//\n// Anti-pattern: builder for a simple object with 2-3 properties;\n//   { a: 1, b: 2 } is simpler than new Builder().setA(1).setB(2).build()."
                  }
        ],
        tips: [
                  "Builder is ideal for objects with many optional parameters — avoids telescoping constructors",
                  "Each setter returns `this` for fluent chaining — always end with `.build()`",
                  "Add validation in `build()` — fail fast if required fields are missing",
                  "Director encapsulates common construction sequences — e.g., standard request presets"
        ],
        mistake: "Using a builder for a simple object with 2-3 properties. A plain object literal `{ a: 1, b: 2 }` is simpler and more readable than `new Builder().setA(1).setB(2).build()`.",
        shorthand: {
          verbose: "// Manual / verbose approach\nconst obj = {};\nobj.a = 1; obj.b = 2; obj.c = 3; obj.d = 4;\n// More explicit but longer",
          concise: "const obj = new Builder().setA(1).setB(2).setC(3).setD(4).build();",
        },
